INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('drug_reference','metformin',ARRAY['ميتفورمين','سكري','جلوكوفاج','سكر الدم'],'ميتفورمين (جلوكوفاج)',E'## ميتفورمين\n\n### الاستخدام\n- خط أول لعلاج السكري النوع 2\n\n### الجرعة\n- بداية: 500 ملغ مرتين يومياً مع الطعام\n- زيادة تدريجية حتى 2000 ملغ/يوم\n\n### آثار جانبية\n- إسهال، غثيان، ألم بطن\n- نقص فيتامين B12 (طويل الأمد)\n\n### موانع\n- فشل كلوي (eGFR < 30)\n- حماض لاكتيكي','ar','BNF',7,true),
('drug_reference','amlodipine',ARRAY['أملوديبين','ضغط','حاصرات الكالسيوم','نورفاسك'],'أملوديبين',E'## أملوديبين\n\n### الاستخدام\n- ارتفاع ضغط الدم\n- الذبحة الصدرية المستقرة\n\n### الجرعة\n- 5-10 ملغ مرة يومياً\n\n### آثار جانبية\n- تورم الكاحل\n- صداع، دوخة\n- احمرار الوجه\n\n### ملاحظات\n- آمن مع أمراض الكلى\n- تجنب مع فشل القلب الحاد','ar','BNF',7,true),
('drug_reference','losartan',ARRAY['لوسارتان','ضغط','حاصرات مستقبلات','كوزار'],'لوسارتان',E'## لوسارتان\n\n### الاستخدام\n- ارتفاع ضغط الدم\n- حماية الكلى في مرضى السكري\n\n### الجرعة\n- 50-100 ملغ مرة يومياً\n\n### آثار جانبية\n- دوخة، ارتفاع البوتاسيوم\n- سعال جاف (أقل من ACEi)\n\n### ⚠️ موانع\n- الحمل (يسبب تشوهات)\n- ضيق الشريان الكلوي الثنائي','ar','BNF',7,true),
('drug_reference','atorvastatin',ARRAY['أتورفاستاتين','كوليسترول','ليبيتور','دهون الدم'],'أتورفاستاتين',E'## أتورفاستاتين\n\n### الاستخدام\n- خفض الكوليسترول والدهون\n- الوقاية من أمراض القلب\n\n### الجرعة\n- 10-80 ملغ مرة يومياً (مساءً)\n\n### آثار جانبية\n- آلام عضلية\n- ارتفاع إنزيمات الكبد\n- نادراً: انحلال العضلات\n\n### مراقبة\n- LFTs قبل البدء ثم سنوياً\n- CK إذا آلام عضلية','ar','BNF',7,true),
('drug_reference','metoprolol',ARRAY['ميتوبرولول','حاصرات بيتا','ضغط','قلب','خفقان'],'ميتوبرولول',E'## ميتوبرولول\n\n### الاستخدام\n- ارتفاع الضغط، الذبحة، عدم انتظام القلب\n- فشل القلب (جرعة منخفضة)\n\n### الجرعة\n- 25-100 ملغ مرتين يومياً\n- ممتد المفعول: 25-200 ملغ مرة يومياً\n\n### آثار جانبية\n- بطء القلب، تعب، برودة الأطراف\n\n### ⚠️ موانع\n- ربو شعبي\n- بطء قلب شديد\n- لا توقفه فجأة','ar','BNF',7,true),
('drug_reference','salbutamol',ARRAY['سالبوتامول','فنتولين','بخاخ','ربو','موسع شعب'],'سالبوتامول (فنتولين)',E'## سالبوتامول\n\n### الاستخدام\n- موسع شعب سريع المفعول\n- نوبات الربو والتشنج الشعبي\n\n### الجرعة\n- بخاخ: 2 بخة عند الحاجة\n- تبخيرة: 2.5-5 ملغ\n\n### آثار جانبية\n- رجفة، خفقان، صداع\n\n### ⚠️ تحذير\n- إذا تحتاج أكثر من 3 مرات/أسبوع = ربو غير مسيطر\n- راجع طبيبك لإضافة علاج وقائي','ar','BNF/GINA',7,true),
('drug_reference','prednisolone',ARRAY['بريدنيزولون','كورتيزون','ستيرويد','التهاب','مناعة'],'بريدنيزولون',E'## بريدنيزولون\n\n### الاستخدام\n- الربو الحاد، الحساسية الشديدة\n- أمراض المناعة الذاتية\n- التهابات مزمنة\n\n### الجرعة\n- حاد: 40-60 ملغ/يوم × 5-7 أيام\n- مزمن: أقل جرعة فعالة\n\n### آثار جانبية (طويل الأمد)\n- سكري، هشاشة عظام\n- زيادة وزن، وجه قمري\n- ضعف مناعة، قرحة معدة\n\n### ⚠️ لا توقفه فجأة إذا > أسبوعين','ar','BNF',7,true),
('drug_reference','amoxicillin',ARRAY['أموكسيسيلين','مضاد حيوي','بنسلين','التهاب','عدوى'],'أموكسيسيلين',E'## أموكسيسيلين\n\n### الاستخدام\n- التهاب الأذن الوسطى\n- التهاب الحلق البكتيري\n- التهاب المسالك البولية\n- عدوى الجهاز التنفسي\n\n### الجرعة\n- بالغ: 500 ملغ كل 8 ساعات\n- أطفال: 25-50 ملغ/كغ/يوم مقسمة\n\n### آثار جانبية\n- إسهال، طفح جلدي\n- حساسية البنسلين\n\n### ⚠️ أكمل الكورس كاملاً','ar','BNF',7,true),
('drug_reference','azithromycin',ARRAY['أزيثروميسين','زيثروماكس','مضاد حيوي','التهاب رئوي'],'أزيثرومايسين',E'## أزيثرومايسين\n\n### الاستخدام\n- التهاب رئوي مكتسب من المجتمع\n- التهاب الحلق (بديل البنسلين)\n- أمراض منقولة جنسياً (كلاميديا)\n\n### الجرعة\n- 500 ملغ يوم 1، ثم 250 ملغ أيام 2-5\n- أو 500 ملغ × 3 أيام\n\n### آثار جانبية\n- غثيان، إسهال\n- إطالة QT (نادر)\n\n### ⚠️ حذر مع أدوية القلب','ar','BNF',7,true),
('drug_reference','ciprofloxacin',ARRAY['سيبروفلوكساسين','سيبرو','مضاد حيوي','مسالك بولية'],'سيبروفلوكساسين',E'## سيبروفلوكساسين\n\n### الاستخدام\n- التهاب مسالك بولية معقد\n- التهاب البروستاتا\n- إسهال بكتيري شديد\n\n### الجرعة\n- 500 ملغ مرتين يومياً × 7-14 يوم\n\n### آثار جانبية\n- تمزق الأوتار (كبار السن)\n- حساسية للشمس\n- غثيان\n\n### ⚠️ موانع\n- الحمل والرضاعة\n- أطفال < 18 سنة\n- صرع','ar','BNF',7,true),
('drug_reference','metronidazole',ARRAY['ميترونيدازول','فلاجيل','طفيليات','لاهوائيات','إسهال'],'ميترونيدازول (فلاجيل)',E'## ميترونيدازول\n\n### الاستخدام\n- عدوى اللاهوائيات\n- الأميبا والجيارديا\n- التهاب المهبل البكتيري\n- جرثومة المعدة (مع أدوية أخرى)\n\n### الجرعة\n- 400-500 ملغ كل 8 ساعات × 7 أيام\n\n### آثار جانبية\n- طعم معدني في الفم\n- غثيان\n\n### ⚠️ ممنوع مع الكحول\n- تفاعل ديسلفيرام خطير','ar','BNF',7,true),
('drug_reference','fluoxetine',ARRAY['فلوكستين','بروزاك','مضاد اكتئاب','SSRI','قلق'],'فلوكستين (بروزاك)',E'## فلوكستين\n\n### الاستخدام\n- الاكتئاب\n- اضطراب القلق\n- الوسواس القهري\n\n### الجرعة\n- 20 ملغ صباحاً\n- يمكن زيادتها حتى 60 ملغ\n\n### آثار جانبية\n- غثيان، أرق، صداع\n- انخفاض الرغبة الجنسية\n\n### ⚠️ تحذيرات\n- يحتاج 2-4 أسابيع للمفعول الكامل\n- لا توقفه فجأة\n- راقب أفكار الانتحار (أول أسبوعين)','ar','BNF/NICE',7,true),
('drug_reference','diazepam',ARRAY['ديازيبام','فاليوم','مهدئ','قلق','تشنجات','أرق'],'ديازيبام (فاليوم)',E'## ديازيبام\n\n### الاستخدام\n- القلق الحاد (قصير الأمد فقط)\n- تشنجات الصرع\n- تشنج العضلات\n- قبل الإجراءات الطبية\n\n### الجرعة\n- قلق: 2-5 ملغ مرتين يومياً\n- تشنجات: 10 ملغ وريدي/شرجي\n\n### ⚠️ تحذيرات خطيرة\n- إدمان إذا > 2-4 أسابيع\n- لا مع كحول أو أفيونات\n- خطر على كبار السن (سقوط)\n- لا يُوصف طويل الأمد','ar','BNF',7,true),
('drug_reference','insulin_rapid',ARRAY['أنسولين سريع','نوفورابيد','هيومالوج','سكري نوع 1'],'الأنسولين سريع المفعول',E'## الأنسولين سريع المفعول\n\n### الأنواع\n- أسبارت (نوفورابيد)\n- ليسبرو (هيومالوج)\n- جلوليزين (أبيدرا)\n\n### الاستخدام\n- قبل الوجبات بـ 15 دقيقة\n- تصحيح ارتفاع السكر\n\n### بداية المفعول: 10-15 دقيقة\n### ذروة: 1-2 ساعة\n### مدة: 3-5 ساعات\n\n### ⚠️ خطر هبوط السكر\n- احمل دائماً سكر سريع\n- لا تحقن بدون أكل','ar','ADA',7,true),
('drug_reference','insulin_long',ARRAY['أنسولين طويل','لانتوس','جلارجين','ليفيمير','سكري'],'الأنسولين طويل المفعول',E'## الأنسولين طويل المفعول\n\n### الأنواع\n- جلارجين (لانتوس) - مرة يومياً\n- ديتيمير (ليفيمير) - مرة أو مرتين\n- ديجلوديك (تريسيبا) - مرة يومياً\n\n### بداية المفعول: 1-2 ساعة\n### لا ذروة واضحة\n### مدة: 20-24 ساعة\n\n### ملاحظات\n- يؤخذ في نفس الوقت يومياً\n- لا يُخلط مع أنسولين آخر (جلارجين)\n- تخزين في الثلاجة (غير مفتوح)','ar','ADA',7,true),
('drug_reference','warfarin',ARRAY['وارفارين','كومادين','مميع دم','INR','جلطة'],'وارفارين',E'## وارفارين\n\n### الاستخدام\n- رجفان أذيني\n- جلطة أوردة عميقة\n- صمامات قلب صناعية\n\n### الجرعة\n- حسب INR المستهدف (عادة 2-3)\n- بداية: 5 ملغ/يوم، تعدل حسب INR\n\n### ⚠️ تحذيرات خطيرة\n- خطر نزيف (كدمات، نزيف لثة، دم بالبول)\n- تفاعلات دوائية كثيرة\n- فحص INR منتظم\n- تجنب الخضروات الورقية بكميات متغيرة\n- ممنوع في الحمل','ar','BNF',7,true),
('drug_reference','aspirin',ARRAY['أسبرين','مسكن','مضاد تجلط','قلب','حمى'],'أسبرين',E'## أسبرين\n\n### الاستخدام\n- مسكن وخافض حرارة: 500-1000 ملغ\n- مضاد تجلط: 75-100 ملغ يومياً\n- نوبة قلبية حادة: 300 ملغ يمضغ\n\n### آثار جانبية\n- ألم معدة، قرحة\n- نزيف\n- طنين (جرعات عالية)\n\n### ⚠️ موانع\n- أطفال < 16 سنة (متلازمة راي)\n- قرحة معدة نشطة\n- حساسية ربو من الأسبرين\n- الثلث الأخير من الحمل','ar','BNF',7,true),
('drug_reference','diclofenac',ARRAY['ديكلوفيناك','فولتارين','مسكن','مضاد التهاب','NSAID'],'ديكلوفيناك',E'## ديكلوفيناك\n\n### الاستخدام\n- آلام المفاصل والعضلات\n- بعد العمليات\n- المغص الكلوي\n\n### الجرعة\n- 50 ملغ مرتين أو 75 ملغ مرة\n- أقصر مدة ممكنة\n\n### آثار جانبية\n- ألم معدة، قرحة\n- خطر قلبي وعائي\n- ارتفاع ضغط\n\n### ⚠️ موانع\n- فشل قلبي\n- فشل كلوي\n- قرحة معدة نشطة\n- الحمل (الثلث الثالث)','ar','BNF',7,true),
('drug_reference','tramadol',ARRAY['ترامادول','مسكن أفيوني','ألم شديد','إدمان'],'ترامادول',E'## ترامادول\n\n### الاستخدام\n- ألم متوسط إلى شديد\n\n### الجرعة\n- 50-100 ملغ كل 4-6 ساعات\n- أقصى: 400 ملغ/يوم\n\n### آثار جانبية\n- غثيان، دوخة، إمساك\n- نعاس\n\n### ⚠️ تحذيرات خطيرة\n- خطر إدمان\n- خطر تشنجات (خاصة مع SSRIs)\n- متلازمة السيروتونين\n- لا مع كحول\n- لا يوصف > 2 أسبوع بدون مراجعة','ar','BNF',7,true),
('drug_reference','doxycycline',ARRAY['دوكسيسيكلين','مضاد حيوي','تتراسيكلين','حب شباب','ملاريا'],'دوكسيسيكلين',E'## دوكسيسيكلين\n\n### الاستخدام\n- حب الشباب\n- الكلاميديا\n- الملاريا (وقاية)\n- التهاب رئوي غير نمطي\n\n### الجرعة\n- 100 ملغ مرتين يومياً × 7 أيام\n- حب شباب: 100 ملغ مرة × 6-12 أسبوع\n\n### آثار جانبية\n- حساسية للشمس\n- قرحة مريء\n\n### ⚠️ تحذيرات\n- اشرب كأس ماء كامل\n- لا تستلقِ بعد تناوله\n- ممنوع في الحمل والأطفال < 12','ar','BNF',7,true),
('drug_reference','omeprazole',ARRAY['أوميبرازول','لوسيك','مضاد حموضة','PPI','قرحة معدة'],'أوميبرازول',E'## أوميبرازول\n\n### الاستخدام\n- قرحة المعدة والاثني عشري\n- ارتجاع المريء (GERD)\n- مع مضادات الالتهاب لحماية المعدة\n- علاج جرثومة المعدة (ثلاثي)\n\n### الجرعة\n- 20-40 ملغ مرة يومياً قبل الإفطار\n\n### آثار جانبية (طويل الأمد)\n- نقص مغنيسيوم، كالسيوم\n- هشاشة عظام\n- نقص B12\n\n### ⚠️ لا يستخدم > 8 أسابيع بدون سبب','ar','BNF',7,true),
('drug_reference','loperamide',ARRAY['لوبيراميد','إيموديوم','إسهال','مضاد إسهال'],'لوبيراميد (إيموديوم)',E'## لوبيراميد\n\n### الاستخدام\n- إسهال حاد (غير بكتيري)\n\n### الجرعة\n- 4 ملغ أولاً ثم 2 ملغ بعد كل إسهال\n- أقصى: 16 ملغ/يوم\n\n### ⚠️ لا تستخدم مع\n- إسهال دموي\n- حمى مع إسهال\n- أطفال < 4 سنوات\n- التهاب القولون الحاد\n\n### ملاحظة\n- استمر بشرب السوائل وORS\n- لا تستخدم > يومين بدون تحسن','ar','BNF',7,true),
('drug_reference','ors',ARRAY['أملاح إرواء','ORS','جفاف','إسهال','محلول ملحي'],'أملاح الإرواء الفموي (ORS)',E'## أملاح الإرواء الفموي\n\n### الاستخدام\n- علاج والوقاية من الجفاف\n- مع الإسهال والقيء\n\n### التحضير\n- كيس واحد في لتر ماء نظيف\n- استخدم خلال 24 ساعة\n\n### الجرعة\n- < سنتين: 50-100 مل بعد كل إسهال\n- 2-10 سنوات: 100-200 مل\n- كبار: حسب الحاجة\n\n### ⚠️ مهم\n- لا تغلي المحلول\n- لا تضف سكر\n- أعطِ بالملعقة إذا يتقيأ\n- زنك مع ORS للأطفال','ar','WHO',7,true),
('drug_reference','ferrous_sulfate',ARRAY['حديد','فيروس سلفات','فقر دم','أنيميا'],'كبريتات الحديد',E'## كبريتات الحديد (فيروس سلفات)\n\n### الاستخدام\n- فقر الدم بنقص الحديد\n\n### الجرعة\n- 325 ملغ (65 ملغ حديد عنصري) 2-3 مرات\n- أطفال: 3-6 ملغ/كغ/يوم\n\n### نصائح\n- خذه مع فيتامين C لتحسين الامتصاص\n- تجنب الشاي والحليب والكالسيوم معه\n- يسبب لون أسود للبراز (طبيعي)\n\n### آثار جانبية\n- إمساك، غثيان\n- ألم بطن\n\n### ⚠️ أبعده عن الأطفال (سام بجرعة عالية)','ar','WHO',7,true),
('drug_reference','folic_acid',ARRAY['حمض فوليك','فولات','حمل','أنيميا','تشوهات'],'حمض الفوليك',E'## حمض الفوليك\n\n### الاستخدام\n- الوقاية من تشوهات الأنبوب العصبي\n- فقر الدم بنقص الفولات\n\n### الجرعة\n- حمل: 400 ميكروغرام يومياً\n- جرعة عالية (صرع/سكري): 5 ملغ يومياً\n- فقر دم: 5 ملغ يومياً × 4 أشهر\n\n### ملاحظات\n- يبدأ قبل الحمل بشهر واحد على الأقل\n- يستمر حتى الأسبوع 12 من الحمل\n- آمن جداً','ar','WHO',7,true),
('drug_reference','vitamin_d',ARRAY['فيتامين دال','فيتامين D','كالسيفيرول','هشاشة عظام','كساح'],'فيتامين D',E'## فيتامين D\n\n### الاستخدام\n- نقص فيتامين D\n- الوقاية من هشاشة العظام\n- الكساح عند الأطفال\n\n### الجرعة\n- نقص: 50,000 وحدة أسبوعياً × 8 أسابيع\n- وقاية: 800-2000 وحدة يومياً\n- رضع: 400 وحدة يومياً\n\n### ملاحظات\n- يؤخذ مع وجبة دهنية\n- فحص المستوى بعد 3 أشهر\n- المستوى الطبيعي > 30 نانوغرام/مل','ar','ES',7,true),
('drug_reference','calcium',ARRAY['كالسيوم','هشاشة عظام','مكمل','كالسيترون'],'كالسيوم',E'## كالسيوم\n\n### الاستخدام\n- هشاشة العظام\n- نقص الكالسيوم\n- مع فيتامين D\n\n### الجرعة\n- 500-1000 ملغ يومياً\n- يفضل كربونات الكالسيوم مع الأكل\n- أو سيترات الكالسيوم (أفضل امتصاص)\n\n### آثار جانبية\n- إمساك، انتفاخ\n- حصوات كلوية (جرعات عالية)\n\n### ⚠️ لا تتجاوز 1500 ملغ/يوم\n- تفاعل مع الحديد والمضادات الحيوية','ar','NOF',7,true),
('drug_reference','montelukast',ARRAY['مونتيلوكاست','سنجولير','ربو','حساسية','لوكوترين'],'مونتيلوكاست',E'## مونتيلوكاست\n\n### الاستخدام\n- الربو (وقائي مساعد)\n- التهاب الأنف التحسسي\n\n### الجرعة\n- بالغ: 10 ملغ مساءً\n- أطفال 6-14: 5 ملغ\n- أطفال 2-5: 4 ملغ\n\n### آثار جانبية\n- صداع\n- ⚠️ تغيرات مزاجية/سلوكية (نادر)\n- أحلام مزعجة\n\n### ملاحظات\n- ليس بديلاً عن البخاخ الكورتيزوني\n- علاج مساعد وليس أساسي','ar','GINA',7,true),
('drug_reference','chlorpheniramine',ARRAY['كلورفينيرامين','مضاد حساسية','مضاد هستامين','رشح','حكة'],'كلورفينيرامين',E'## كلورفينيرامين\n\n### الاستخدام\n- الحساسية (رشح، حكة، شرى)\n- لسعات الحشرات\n\n### الجرعة\n- بالغ: 4 ملغ كل 4-6 ساعات\n- أطفال 6-12: 2 ملغ\n- أطفال 2-5: 1 ملغ\n\n### آثار جانبية\n- نعاس (الأكثر شيوعاً)\n- جفاف الفم\n\n### ⚠️ تحذيرات\n- لا تقُد السيارة\n- حذر مع كبار السن\n- حذر مع احتباس البول','ar','BNF',7,true),
